/**
 * ============================================================
 * PROCESO: Consulta automatizada de procesos judiciales
 * ============================================================
 * 
 * OBJETIVO:
 * Automatizar la consulta por nombre en el portal de la Rama Judicial
 * y capturar el resultado, priorizando la descarga DOC O EN SU DEFECTO en CSV directamente
 * en memoria sin necesidad de guardar archivos.
 * 
 *  ENTRADA:
 * - nombre: String obtenido desde el input del flujo
 * 
 * SALIDA:
 * - nombre_consultado
 * - filas_encontradas
 * - tipo de descarga (DOC | CSV)
 * - contenido CSV (si disponible)
 * - estado del proceso
 * 
 * TECNOLOGÍA:
 * - Puppeteer (automatización de navegador)
 * ============================================================
 */

const nombre = $input.first().json.snippet;

const codigo = `
module.exports = async ({ page }) => {

  // ============================================================
  // 1. NAVEGACIÓN AL PORTAL
  // ============================================================
  await page.goto(
    'https://consultaprocesos.ramajudicial.gov.co/Procesos/NombreRazonSocial',
    { waitUntil: 'networkidle2', timeout: 30000 }
  );

  // Espera a que cargue el grupo de opciones (radio buttons)
  await page.waitForSelector('.v-input--radio-group', { timeout: 30000 });


  // ============================================================
  // 2. SELECCIÓN DE TIPO DE PERSONA
  // ============================================================

  // Selecciona el radio correspondiente (value="false")
  await page.evaluate(() => {
    const radios = document.querySelectorAll('input[type="radio"]');
    for (const r of radios) {
      if (r.getAttribute('value') === 'false') { 
        r.click(); 
        break; 
      }
    }
  });

  // Abre el dropdown de tipo de persona
  await page.evaluate(() => {
    const inputs = document.querySelectorAll('input[readonly]');
    if (inputs[0]) inputs[0].click();
  });

  // Selecciona "Natural" del menú desplegable
  await page.waitForSelector('.v-menu__content', { visible: true, timeout: 10000 });
  await page.evaluate(() => {
    const items = document.querySelectorAll('.v-menu__content .v-list-item');
    for (const item of items) {
      if (item.textContent.includes('Natural')) { 
        item.click(); 
        break; 
      }
    }
  });


  // ============================================================
  // 3. INGRESO DEL NOMBRE A CONSULTAR
  // ============================================================
  const inputNombre = await page.waitForSelector(
    'xpath///label[contains(text(),"* Nombre(s) Apellido o Razón Social")]/following::input[1]',
    { timeout: 10000 }
  );

  await inputNombre.focus();

  // Limpia el campo antes de escribir
  await inputNombre.evaluate(el => el.value = '');

  // Escribe el nombre recibido como entrada
  await inputNombre.type('${nombre}');


  // ============================================================
  // 4. EJECUCIÓN DE LA CONSULTA
  // ============================================================
  await page.evaluate(() => {
    const spans = document.querySelectorAll('button span');
    for (const span of spans) {
      if (span.textContent.trim() === 'Consultar') { 
        span.closest('button').click(); 
        break; 
      }
    }
  });

  // Manejo opcional de pantalla intermedia con botón "Volver"
  try {
    await page.waitForSelector('button span', { timeout: 5000 });
    await page.evaluate(() => {
      const spans = document.querySelectorAll('button span');
      for (const span of spans) {
        if (span.textContent.trim() === 'Volver') { 
          span.closest('button').click(); 
          break; 
        }
      }
    });
  } catch(e) {}


  // ============================================================
  // 5. PROCESAMIENTO DE RESULTADOS
  // ============================================================
  await page.waitForSelector('table tbody tr', { timeout: 30000 });

  const resultado = await page.evaluate(() => {
    const filas = document.querySelectorAll('table tbody tr');

    // Validación de resultados mínimos
    if (filas.length < 6) {
      return { error: 'No hay suficientes filas', filas: filas.length };
    }

    // Selecciona el botón de la fila 6
    const boton = filas[5].querySelector('td:nth-child(2) button');

    if (boton) { 
      boton.click(); 
      return { ok: true, filas: filas.length }; 
    }

    return { error: 'Botón no encontrado' };
  });

  // Si ocurre error, retornar inmediatamente
  if (resultado.error) return { data: resultado };

  await new Promise(r => setTimeout(r, 2000));


  // ============================================================
  // 6. INTERCEPCIÓN DE DESCARGA (CSV EN MEMORIA)
  // ============================================================
  let csvContenido = null;

  await page.setRequestInterception(true);

  // Permitir todas las solicitudes
  page.on('request', req => req.continue());

  // Capturar respuestas que contengan CSV
  page.on('response', async response => {
    const url = response.url();

    if (
      url.includes('csv') || 
      url.includes('CSV') || 
      url.includes('export') || 
      url.includes('download')
    ) {
      try {
        csvContenido = await response.text();
      } catch(e) {}
    }
  });


  // ============================================================
  // 7. INTENTO DE DESCARGA (DOC → CSV)
  // ============================================================

  // Intentar descargar DOC primero
  const docClickado = await page.evaluate(() => {
    const spans = document.querySelectorAll('span');
    for (const span of spans) {
      if (span.textContent.trim() === 'DOC') {
        const boton = span.closest('button');
        if (boton) { 
          boton.click(); 
          return true; 
        }
      }
    }
    return false;
  });

  let descarga = 'DOC';

  if (docClickado) {
    await new Promise(r => setTimeout(r, 2000));

    // Validar si el DOC no está disponible
    try {
      const modalTexto = await page.$eval('.v-dialog--active', el => el.textContent.toLowerCase());

      if (modalTexto.includes('no está disponible')) {

        // Cerrar modal
        await page.evaluate(() => {
          const spans = document.querySelectorAll('.v-dialog--active span');
          for (const span of spans) {
            if (span.textContent.trim() === 'Volver') { 
              span.closest('button').click(); 
              break; 
            }
          }
        });

        await page.waitForSelector('.v-dialog--active', { hidden: true, timeout: 10000 });

        // Fallback a CSV
        descarga = 'CSV';
      }
    } catch(e) {}

  } else {
    descarga = 'CSV';
  }


  // ============================================================
  // 8. DESCARGA Y CAPTURA DE CSV
  // ============================================================
  if (descarga === 'CSV') {

    // Reintenta hasta 3 veces encontrar el botón
    for (let i = 0; i < 3; i++) {

      const csvOk = await page.evaluate(() => {
        const spans = document.querySelectorAll('span');

        for (const span of spans) {
          if (span.textContent.trim() === 'Descargar CSV') {
            const boton = span.closest('button');

            // Validar que el botón esté visible
            if (boton && boton.offsetParent !== null) { 
              boton.click(); 
              return true; 
            }
          }
        }
        return false;
      });

      if (csvOk) { 
        await new Promise(r => setTimeout(r, 3000));
        break; 
      }

      await new Promise(r => setTimeout(r, 2000));
    }
  }


  // ============================================================
  // 9. RESPUESTA FINAL
  // ============================================================
  return {
    data: {
      nombre_consultado: '${nombre}',
      filas_encontradas: resultado.filas,
      descarga: descarga,
      csvContenido: csvContenido || 'No se pudo capturar el contenido',
      status: 'completado'
    }
  };
};
`;

return [{
  json: {
    code: codigo,
    context: {}
  }
}];

/**
 * ============================================================
 * PROCESO: GENERACIÓN DE ARCHIVO FINAL
 * ============================================================
 * 
 * OBJETIVO:
 * - Si llega CSV → convertir a documento Word (.doc) con formato tipo ficha
 * - Si llega DOC/DOCX → enviar archivo original sin modificar
 * 
 * CARACTERÍSTICAS:
 * ✔ Manejo de CSV complejo (sep=;, comillas, formato Excel)
 * ✔ No rompe el flujo (manejo de errores)
 * ✔ Formato legible tipo informe
 * ✔ Compatible con Word sin errores
 * 
 * ============================================================
 */

let buffer;
let fileName;
let mimeType;

// DEFINIDA GLOBAL (ANTES DEL TRY)
const ahora = new Date();

const fechaHora = ahora.toLocaleString('sv-SE', {
  timeZone: 'America/Bogota',
}).replace(' ', '_').replace(/:/g, '-');


try {

  // ============================================================
  // 1. OBTENER Y PARSEAR DATOS DE ENTRADA
  // ============================================================
  // Puede venir como string JSON o como objeto
  let raw = $input.first().json.data;

  let data;
  try {
    data = typeof raw === 'string' ? JSON.parse(raw) : raw;
  } catch (e) {
    // fallback si el JSON viene mal formado
    data = raw || {};
  }

  // ============================================================
  // 2. DETECTAR TIPO DE ARCHIVO
  // ============================================================
  // Si hay csvContenido → es CSV
  // Si no → se asume DOC/DOCX
  const tipo = data.tipo || (data.csvContenido ? 'csv' : 'doc');

  // ============================================================
  // 3. GENERAR FECHA Y HORA (ZONA COLOMBIA)
  // ============================================================
  const ahora = new Date();
  const fechaHora = ahora.toLocaleString('sv-SE', {
    timeZone: 'America/Bogota',
  }).replace(' ', '_').replace(/:/g, '-');

  // ============================================================
  // 4. PROCESAMIENTO SI ES CSV
  // ============================================================
  if (tipo === 'csv') {

    /**
     * PROBLEMAS QUE RESUELVE ESTE BLOQUE:
     * - CSV con "sep=;" (formato Excel)
     * - CSV con datos entre comillas
     * - Valores tipo ="12345"
     * - Líneas mal separadas
     */

    let csv = (data.csvContenido || '')
      .replace(/\u0000/g, '') // eliminar caracteres invisibles
      .trim();

    // normalizar saltos de línea
    csv = csv.replace(/\r/g, '');

    // asegurar que sep=; esté separado
    csv = csv.replace('sep=;', 'sep=;\n');

    const lineas = csv.split('\n').filter(Boolean);

    let separador = ';';
    let startIndex = 0;

    // detectar separador dinámico
    if (lineas[0].startsWith('sep=')) {
      separador = lineas[0].split('=')[1] || ';';
      startIndex = 1;
    }

    // ============================================================
    // 4.1 EXTRAER HEADERS
    // ============================================================
    const headers = (lineas[startIndex] || '')
      .split(separador)
      .map(h => h.trim())
      .filter(Boolean);

    // ============================================================
    // 4.2 EXTRAER FILA DE DATOS
    // ============================================================
    const dataLinea = lineas[startIndex + 1] || '';

    /**
     * Parser personalizado:
     * - Respeta texto entre comillas
     * - No rompe cuando hay ; dentro del texto
     */
    function parseFila(fila) {

      let valores = [];
      let actual = '';
      let dentroComillas = false;

      for (let i = 0; i < fila.length; i++) {
        const char = fila[i];

        if (char === '"') {
          dentroComillas = !dentroComillas;
          continue;
        }

        if (char === separador && !dentroComillas) {
          valores.push(actual.trim());
          actual = '';
        } else {
          actual += char;
        }
      }

      valores.push(actual.trim());

      // limpiar formato Excel ="valor"
      return valores.map(v =>
        v.replace(/^=/, '').trim()
      );
    }

    const columnas = parseFila(dataLinea);

    // ============================================================
    // 4.3 GENERAR TABLA TIPO FICHA
    // ============================================================
    const tbody = headers.map((header, i) => `
      <tr>
        <td style="background:#2b436b;color:white;font-weight:bold;width:30%;">
          ${header}
        </td>
        <td style="width:70%;">
          ${columnas[i] || ''}
        </td>
      </tr>
    `).join('');

    // ============================================================
    // 4.4 GENERAR HTML COMPATIBLE CON WORD
    // ============================================================
    const html = `
    <html>
      <head><meta charset="UTF-8"></head>
      <body style="font-family:Calibri; margin:25px;">

        <h2 style="background:#d9d9d9;padding:8px;">Resultados de consulta</h2>

        <p><b>Nombre:</b> ${data.nombre_consultado || 'N/A'}</p>
        <p><b>Fecha de la consulta:</b> ${fechaHora}</p>

        <table border="1" cellspacing="0" cellpadding="6" style="width:100%;border-collapse:collapse;">
          ${tbody}
        </table>

      </body>
    </html>
    `;

    buffer = Buffer.from(html, 'utf-8');

    fileName = `procesos_${(data.nombre_consultado || 'sin_nombre').replace(/ /g, '_')}_${fechaHora}.doc`;

    mimeType = 'application/msword';
  }

  // ============================================================
  // 5. SI ES DOC O DOCX → SE ENVÍA ORIGINAL
  // ============================================================
  else {

    /**
     * No se transforma el archivo
     * Solo se reconstruye desde base64
     */
    buffer = Buffer.from(data.fileBase64 || '', 'base64');

    const extension = tipo === 'docx' ? 'docx' : 'doc';

    fileName = `procesos_${(data.nombre_consultado || 'sin_nombre').replace(/ /g, '_')}_${fechaHora}.${extension}`;

    mimeType = tipo === 'docx'
      ? 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
      : 'application/msword';
  }

} catch (error) {

  // ============================================================
  // 6. MANEJO DE ERRORES (NO ROMPE FLUJO)
  // ============================================================
  const htmlError = `
  <html>
    <body>
      <h2>Error en procesamiento</h2>
      <pre>${error.message}</pre>
    </body>
  </html>
  `;

  buffer = Buffer.from(htmlError, 'utf-8');
  fileName = `error.doc`;
  mimeType = 'application/msword';
}

// ============================================================
// 7. PREPARAR ARCHIVO BINARIO PARA SALIDA
// ============================================================
const binaryData = await this.helpers.prepareBinaryData(
  buffer,
  fileName,
  mimeType
);

// ============================================================
// 8. RESPUESTA FINAL
// ============================================================
return [{
  json: {
    fileName,
    fechaHora
  },
  binary: {
    attachment: binaryData
  }
}];

const log = {
  timestamp: new Date().toISOString(),
  step: "Consulta Judicial",
  status: $json.error ? "error" : "success",
  message: $json.error ? "Falló la consulta" : "Consulta ejecutada",
  nombre: $json.nombre || "NODO PROCEZAMIENTO SCRAPING",
  error_stack: $json.error?.stack || null
};

return [{
  json: { log }
}];

